import { describe, expect, it } from "vitest";
import { parseQuery } from "../src/parseQuery.js";

// Behavior under test is documented in src/parseQuery.js. Each test asserts a
// specific, exact output so a regression in the parser fails loudly.

describe("parseQuery", () => {
  describe("leading '?' handling", () => {
    it("strips a single leading '?'", () => {
      expect(parseQuery("?a=1")).toEqual({ a: "1" });
    });

    it("parses identically with or without a leading '?'", () => {
      expect(parseQuery("?a=1&b=2")).toEqual(parseQuery("a=1&b=2"));
    });

    it("strips only the first '?', leaving a second one in the key", () => {
      expect(parseQuery("??a=1")).toEqual({ "?a": "1" });
    });

    it("does not strip a '?' that is not at the start", () => {
      expect(parseQuery("a?=1")).toEqual({ "a?": "1" });
    });

    it("treats a lone '?' as an empty query", () => {
      expect(parseQuery("?")).toEqual({});
    });
  });

  describe("empty input", () => {
    it("returns an empty object for the empty string", () => {
      expect(parseQuery("")).toEqual({});
    });

    it("returns a plain object", () => {
      expect(typeof parseQuery("")).toBe("object");
    });
  });

  describe("pair separation and empty segments", () => {
    it("separates pairs on '&'", () => {
      expect(parseQuery("a=1&b=2&c=3")).toEqual({ a: "1", b: "2", c: "3" });
    });

    it("skips empty segments between pairs ('a=1&&b=2')", () => {
      expect(parseQuery("a=1&&b=2")).toEqual({ a: "1", b: "2" });
    });

    it("skips a leading empty segment", () => {
      expect(parseQuery("&a=1")).toEqual({ a: "1" });
    });

    it("skips a trailing empty segment", () => {
      expect(parseQuery("a=1&")).toEqual({ a: "1" });
    });

    it("skips a run of consecutive '&' separators", () => {
      expect(parseQuery("&&&a=1&&&")).toEqual({ a: "1" });
    });

    it("returns an empty object when every segment is empty", () => {
      expect(parseQuery("&&&")).toEqual({});
    });
  });

  describe("single occurrence keys", () => {
    it("maps a key that appears once to its string value", () => {
      expect(parseQuery("a=1")).toEqual({ a: "1" });
    });

    it("keeps the value as a string, not a number", () => {
      expect(parseQuery("a=1").a).toBe("1");
    });

    it("splits only on the first '=', keeping later '=' in the value", () => {
      expect(parseQuery("a=b=c")).toEqual({ a: "b=c" });
    });

    it("allows an empty value after '='", () => {
      expect(parseQuery("a=")).toEqual({ a: "" });
    });

    it("allows an empty key before '='", () => {
      expect(parseQuery("=value")).toEqual({ "": "value" });
    });

    it("allows both key and value empty ('=')", () => {
      expect(parseQuery("=")).toEqual({ "": "" });
    });
  });

  describe("repeated keys", () => {
    it("maps a key that appears twice to an array of its values", () => {
      expect(parseQuery("a=1&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("preserves order of appearance across three occurrences", () => {
      expect(parseQuery("a=1&a=2&a=3")).toEqual({ a: ["1", "2", "3"] });
    });

    it("keeps the repeated value as an array even with empty segments between", () => {
      expect(parseQuery("a=1&&a=2")).toEqual({ a: ["1", "2"] });
    });

    it("groups only repeated keys, leaving single keys as strings", () => {
      expect(parseQuery("a=1&b=2&a=3")).toEqual({ a: ["1", "3"], b: "2" });
    });

    it("promotes a bare key followed by a valued occurrence to an array", () => {
      expect(parseQuery("a&a=2")).toEqual({ a: ["", "2"] });
    });

    it("collects repeated bare keys as an array of empty strings", () => {
      expect(parseQuery("flag&flag")).toEqual({ flag: ["", ""] });
    });
  });

  describe("bare keys (no '=')", () => {
    it("maps a bare key to an empty string", () => {
      expect(parseQuery("flag")).toEqual({ flag: "" });
    });

    it("maps multiple distinct bare keys each to an empty string", () => {
      expect(parseQuery("a&b&c")).toEqual({ a: "", b: "", c: "" });
    });
  });

  describe("'+' decoding to space", () => {
    it("decodes '+' to a space in values", () => {
      expect(parseQuery("a=c+d")).toEqual({ a: "c d" });
    });

    it("decodes '+' to a space in keys", () => {
      expect(parseQuery("a+b=1")).toEqual({ "a b": "1" });
    });

    it("decodes '+' in both key and value", () => {
      expect(parseQuery("a+b=c+d")).toEqual({ "a b": "c d" });
    });

    it("decodes multiple '+' characters", () => {
      expect(parseQuery("a=x+y+z")).toEqual({ a: "x y z" });
    });
  });

  describe("percent decoding", () => {
    it("percent-decodes values", () => {
      expect(parseQuery("a=%20")).toEqual({ a: " " });
    });

    it("percent-decodes keys", () => {
      expect(parseQuery("k%65y=v")).toEqual({ key: "v" });
    });

    it("decodes a percent-encoded '&' inside a value without splitting on it", () => {
      expect(parseQuery("a=1%262")).toEqual({ a: "1&2" });
    });

    it("decodes a percent-encoded '=' inside a value", () => {
      expect(parseQuery("a=1%3D2")).toEqual({ a: "1=2" });
    });

    it("decodes multi-byte UTF-8 sequences", () => {
      expect(parseQuery("a=%E2%9C%93")).toEqual({ a: "✓" });
    });

    it("replaces '+' before percent-decoding, so '%2B' yields a literal '+'", () => {
      expect(parseQuery("a=%2B")).toEqual({ a: "+" });
    });

    it("decodes a lone '+' to a space (not a literal plus)", () => {
      expect(parseQuery("a=+")).toEqual({ a: " " });
    });
  });

  describe("decode failure fallback", () => {
    it("uses the raw token when a value cannot be percent-decoded", () => {
      expect(parseQuery("a=%")).toEqual({ a: "%" });
    });

    it("uses the raw token for an invalid percent escape", () => {
      expect(parseQuery("a=%ZZ")).toEqual({ a: "%ZZ" });
    });

    it("uses the raw token for a truncated multi-byte sequence", () => {
      expect(parseQuery("a=%E0%A4%A")).toEqual({ a: "%E0%A4%A" });
    });

    it("uses the raw token when a key cannot be decoded", () => {
      expect(parseQuery("%=v")).toEqual({ "%": "v" });
    });

    it("still applies '+' replacement in the fallback path", () => {
      expect(parseQuery("a=%+b")).toEqual({ a: "% b" });
    });

    it("does not throw on undecodable input", () => {
      expect(() => parseQuery("a=%&b=%GG")).not.toThrow();
    });

    it("falls back per-token, decoding valid siblings normally", () => {
      expect(parseQuery("a=%&b=%20")).toEqual({ a: "%", b: " " });
    });
  });

  describe("combined scenarios", () => {
    it("handles a realistic mixed query string", () => {
      expect(parseQuery("?q=hello+world&tag=a&tag=b&flag&empty=")).toEqual({
        q: "hello world",
        tag: ["a", "b"],
        flag: "",
        empty: "",
      });
    });

    it("decodes '+' and '%20' identically to spaces", () => {
      expect(parseQuery("a=x+y")).toEqual(parseQuery("a=x%20y"));
    });

    it("decodes both key and value with a mix of '+' and '%'", () => {
      expect(parseQuery("%20=%20")).toEqual({ " ": " " });
    });
  });
});

